class TreeNode:
    def __init__(self, val=0, left=None, right=None):
        self.val = val
        self.left = left
        self.right = right
def same_tree(a: TreeNode, b: TreeNode) -> bool:
    if not a and not b:
        return True
    if not a or not b:
        return False
    if a.val != b.val:
        return False
    return same_tree(a.left, b.left) and same_tree(a.right, b.right)

